以下是uniapp中使用安卓微信第三方登录的代码示例：

1. 在HBuilderX中创建一个uni-app项目，选择空项目，然后添加微信插件

2. 在项目的manifest.json文件中配置权限：

```
"permission": { 
    "scope.userLocation": {
        "desc": "小程序朋友圈位置信息",
    }
}
```

3. 在App.vue中引入并初始化微信插件

```javascript
import InitWx from "@/common/common.js"; 
InitWx(); 
```

4. 在common.js文件中初始化微信插件（需要下载WeixinJSBridge.js，放入common文件夹中）

```javascript
export default function InitWx() { 
    const startConfig = () => { 
      	// 验证配置，验证通过后触发ready事件
        wx.checkJsApi({
            'jsApiList': [
                'login'
            ],
            'success': function (res) {
                //验证成功 
                wx.onReady(() => {
                    console.log("微信环境准备就绪");
                });
            },
            'fail': function () {
                console.warn('微信验证失败');
            }
        });
  	};

  	if (!window.WeixinJSBridge || !WeixinJSBridge.invoke) {
        document.addEventListener('WeixinJSBridgeReady', startConfig, false);
    } else {
        setTimeout(() => {
            startConfig();
        }, 0);
    }
}
```

5. 在需要使用微信第三方登录的页面中调用login方法获取code值

```javascript
wx.login({
    success: function (res) {
        if (res.code) {
            //获取到用户的code值，进行下一步操作
            console.log('获取用户code成功：' + res.code);
        } else {
            console.log('获取用户code失败');
        }
    },
    fail: function (res) {
        console.log('调用login接口失败');
    }
});
```

6. 使用code值向服务器请求access_token和openid，并获取用户信息

```javascript
//使用code请求access_token
const oauthUrl = `https://api.weixin.qq.com/sns/oauth2/access_token?appid=${appId}&secret=${appSecret}&code=${code}&grant_type=authorization_code`;
uni.request({
    url: oauthUrl,
    method: 'GET',
    dataType: 'json',
    success: (res) => {
        let data = res.data;
        if (data.access_token) {

          	//使用access_token和openid获取用户信息
            const infoUrl = `https://api.weixin.qq.com/sns/userinfo?access_token=${data.access_token}&openid=${data.openid}`;
            uni.request({
                url: infoUrl,
                method: 'GET',
                dataType: 'json',
                success: (res) => {
                    console.log('获取到用户信息：' + JSON.stringify(res.data));
                },
                fail: (res) => {
                    console.log('获取用户信息失败');
                }
            });
        } else {
            console.log('获取access_token失败');
        }
    },
    fail: (res) => {
        console.log('获取access_token失败');
    }
});
```

以上就是使用uni-app在安卓微信获取第三方登录的操作流程和代码实现。
